@import 'tailwindcss';
@import 'tw-animate-css';

@custom-variant dark (&:is(.dark *));

:root {
  --background: oklch(0.12 0.01 250);
  --foreground: oklch(0.98 0 0);
  --card: oklch(0.18 0.01 250 / 0.8);
  --card-foreground: oklch(0.98 0 0);
  --popover: oklch(0.15 0.01 250 / 0.95);
  --popover-foreground: oklch(0.98 0 0);
  --primary: oklch(0.65 0.2 250);
  --primary-foreground: oklch(0.98 0 0);
  --secondary: oklch(0.25 0.01 250);
  --secondary-foreground: oklch(0.98 0 0);
  --muted: oklch(0.30 0.01 250);
  --muted-foreground: oklch(0.70 0 0);
  --accent: oklch(0.55 0.15 180);
  --accent-foreground: oklch(0.98 0 0);
  --destructive: oklch(0.55 0.2 25);
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.35 0.01 250);
  --input: oklch(0.25 0.01 250);
  --ring: oklch(0.65 0.2 250);
  --chart-1: oklch(0.65 0.2 250);
  --chart-2: oklch(0.55 0.15 180);
  --chart-3: oklch(0.65 0.15 140);
  --chart-4: oklch(0.70 0.18 50);
  --chart-5: oklch(0.60 0.2 350);
  --radius: 0.75rem;

  /* macOS specific colors */
  --macos-titlebar: oklch(0.22 0.01 250 / 0.85);
  --macos-dock: oklch(0.20 0.01 250 / 0.7);
  --macos-window: oklch(0.18 0.01 250 / 0.9);
  --macos-menubar: oklch(0.15 0.01 250 / 0.8);
  --macos-close: oklch(0.65 0.2 25);
  --macos-minimize: oklch(0.75 0.2 90);
  --macos-maximize: oklch(0.65 0.2 145);
}

@theme inline {
  --font-sans: 'SF Pro Display', 'Geist', system-ui, sans-serif;
  --font-mono: 'SF Mono', 'Geist Mono', monospace;
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
}

/* macOS Window Styles */
.macos-window {
  backdrop-filter: blur(40px);
  -webkit-backdrop-filter: blur(40px);
  box-shadow: 
    0 25px 50px -12px rgba(0, 0, 0, 0.5),
    0 0 0 1px rgba(255, 255, 255, 0.1) inset;
}

.macos-titlebar {
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
}

.macos-dock {
  backdrop-filter: blur(30px);
  -webkit-backdrop-filter: blur(30px);
  box-shadow: 
    0 0 30px rgba(0, 0, 0, 0.3),
    0 0 0 1px rgba(255, 255, 255, 0.1) inset;
}

.macos-menubar {
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
}

.ios-ipad-bar {
  background: linear-gradient(
    180deg,
    oklch(0.22 0.04 250 / 0.92) 0%,
    oklch(0.18 0.03 250 / 0.88) 100%
  );
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  border-bottom: 1px solid oklch(1 0 0 / 0.08);
}

.ios-safe-top {
  padding-top: max(0.35rem, env(safe-area-inset-top, 0px));
}

.ios-dock-pill {
  background: oklch(0.2 0.02 250 / 0.55);
  backdrop-filter: blur(40px) saturate(180%);
  -webkit-backdrop-filter: blur(40px) saturate(180%);
  border-radius: 1.35rem;
  border: 1px solid oklch(1 0 0 / 0.12);
  box-shadow:
    0 12px 40px rgba(0, 0, 0, 0.35),
    inset 0 1px 0 oklch(1 0 0 / 0.08);
}

.ios-tablet-window {
  background: oklch(0.14 0.012 250 / 0.96);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  box-shadow:
    0 24px 60px rgba(0, 0, 0, 0.45),
    0 0 0 1px oklch(1 0 0 / 0.12) inset;
}

.ios-phone-sheet {
  background: oklch(0.13 0.012 250 / 0.97);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  box-shadow: 0 -8px 40px rgba(0, 0, 0, 0.4);
  border: 1px solid oklch(1 0 0 / 0.1);
  border-bottom: none;
}

.ios-phone-title {
  background: linear-gradient(
    180deg,
    oklch(0.28 0.03 250 / 0.95),
    oklch(0.22 0.02 250 / 0.92)
  );
  border-bottom: 1px solid oklch(1 0 0 / 0.08);
}

.ios-ipad-titlebar {
  background: linear-gradient(
    180deg,
    oklch(0.24 0.02 250 / 0.92),
    oklch(0.2 0.02 250 / 0.88)
  );
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid oklch(1 0 0 / 0.08);
}

.pb-safe {
  padding-bottom: max(0.35rem, env(safe-area-inset-bottom, 0px));
}

/* Evita cursor de texto / “palito” en iconos del escritorio (role=button, no <button>) */
.desktop-icon-hit,
.desktop-icon-label {
  user-select: none;
  -webkit-user-select: none;
  -moz-user-select: none;
  caret-color: transparent;
}

/* Window animations */
@keyframes windowOpen {
  from {
    opacity: 0;
    transform: scale(0.8);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes windowClose {
  from {
    opacity: 1;
    transform: scale(1);
  }
  to {
    opacity: 0;
    transform: scale(0.8);
  }
}

.window-open {
  animation: windowOpen 0.2s ease-out forwards;
}

.window-close {
  animation: windowClose 0.15s ease-in forwards;
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.2);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.3);
}

