          >
            {sent ? (
              "Se abrió WhatsApp — revisá la pestaña"
            ) : (
              <>
                <WhatsAppGlyph className="h-5 w-5" />
                Enviar por WhatsApp
              </>
            )}
          </button>
        </form>
      </div>
    </div>
  );
}

